function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function sqlLiteral(value) {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlJson(value) {
  return `${sqlLiteral(JSON.stringify(value ?? null))}::jsonb`;
}

function normalizeContentType(value) {
  const normalized = String(value || '').trim().toLowerCase().replace(/\s*-\s*/g, '_').replace(/[\s-]+/g, '_');
  const map = { single_image: 'single_image', story_image: 'story_image', carousel: 'carousel', reels: 'reels', story_video: 'story_video' };
  return map[normalized] || 'text_only';
}

