const productContext = parseMaybeJson(row.product_context, null) || { id: req.product.id || '', name: req.product.name || '' };
const topicContext = parseMaybeJson(row.topic_context, null) || req.topic || {};

const skills = [
  { slug: 'copywriting', name: 'Copywriting', content: 'Create persuasive copy with a clear hook, audience-specific angle, concrete benefit, strong structure, and a CTA that matches the objective. Keep claims grounded in available context.' },
  { slug: 'copy-editing', name: 'Copy Editing', content: 'Tighten wording, remove fluff, keep grammar natural, improve clarity, and make every line readable for the requested language, platform, and format.' },
  { slug: 'social-content', name: 'Social Content', content: 'Adapt the content to social media behavior. Match the platform, format, and consumption pattern. Make hooks fast, captions useful, visuals actionable, and slides or scenes easy to follow.' },
  { slug: 'ad-creative', name: 'Ad Creative', content: 'Use strong creative framing: problem-solution, contrast, transformation, proof, objections, emotional trigger, or curiosity. Make the content executable as a campaign asset.' },
  { slug: 'marketing-psychology', name: 'Marketing Psychology', content: 'Apply customer motivation, pain points, objections, decision triggers, urgency, trust, and value perception. Do not invent facts, proof, or offers that are absent from the context.' }
];

const skillsContext = skills.map((skill) => `## ${skill.name}\n${skill.content}`).join('\n\n---\n\n');
const referenceImagesText = Array.isArray(req.referenceImages) && req.referenceImages.length
  ? req.referenceImages.map((image, index) => `${index + 1}. ${typeof image === 'string' ? image : JSON.stringify(image)}`).join('\n')
  : 'None';

return [{
  json: {
    jobId: req.jobId,
    brand: req.brand,
    product: req.product,
    topic: req.topic,
    brand_context: brandContext,
    product_context: productContext,
    topic_context: topicContext,
    brand_context_text: asText(brandContext),
    product_context_text: asText(productContext),
