function stripCodeFence(text) {
  return String(text || '').trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
}

function parseAiJson(value) {
  if (value && typeof value === 'object' && !Array.isArray(value)) return value;

  const cleaned = stripCodeFence(value);

  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const first = cleaned.indexOf('{');
    const last = cleaned.lastIndexOf('}');

    if (first >= 0 && last > first) {
      return JSON.parse(cleaned.slice(first, last + 1));
    }

    throw error;
  }
}

function firstReferenceImageUrl(value) {
  if (!value) return null;

  if (Array.isArray(value)) {
    const first = value.find(Boolean);
    return first ? String(first) : null;
  }

  return String(value);
}

const built = $('Build Content Context + Skills Context').first().json;
const webhookBody = $('Webhook - Content Generator').first().json.body || {};
const incoming = $input.first().json || {};

const referenceImageUrl =
  firstReferenceImageUrl(webhookBody.referenceImages) ||
  firstReferenceImageUrl(built.referenceImages) ||
  firstReferenceImageUrl(incoming.referenceImages);

const raw = incoming.output ?? incoming.text ?? incoming.response ?? incoming;
const parsed = parseAiJson(raw);

const slides = Array.isArray(parsed.slides) ? parsed.slides : [];
if (!slides.length) throw new Error('Carousel output must include slides');

const normalizedSlides = slides.map((slide, index) => ({
  slideNumber: Number(slide.slideNumber || index + 1),
  headline: String(slide.headline || ''),
  body: String(slide.body || ''),
  visualDirection: String(slide.visualDirection || ''),
  imagePrompt: String(slide.imagePrompt || slide.visualDirection || '').trim(),
  imageUrl: null,
  referenceImageUrl,
  aspectRatio: '1:1',
}));

const content = {
  title: String(parsed.title || built.topic?.title || ''),
  platform: String(parsed.platform || built.platform || built.topic?.platform || ''),
  objective: String(parsed.objective || built.objective || ''),
  format: 'carousel',
  caption: String(parsed.caption || ''),
  hook: String(parsed.hook || ''),
  cta: String(parsed.cta || ''),
  hashtags: Array.isArray(parsed.hashtags) ? parsed.hashtags : [],
  slides: normalizedSlides,
};

const sections = [
  { sectionType: 'hook', sectionOrder: 1, contentText: content.hook || '' },
  { sectionType: 'caption', sectionOrder: 2, contentText: content.caption || '' },
  { sectionType: 'cta', sectionOrder: 3, contentText: content.cta || '' },
  { sectionType: 'hashtag', sectionOrder: 4, contentText: content.hashtags.join(' ') },
  ...normalizedSlides.map((slide, index) => ({
    sectionType: 'slide',
    sectionOrder: index + 5,
    contentText: JSON.stringify(slide),
  })),
];

const images = normalizedSlides.map((slide) => ({
  type: 'slide',
  slideNumber: slide.slideNumber,
  imagePrompt: slide.imagePrompt,
  imageUrl: null,
  referenceImageUrl,
  aspectRatio: '1:1',
}));

return [
  {
    json: {
      jobId: built.jobId,
      content,
      sections,
      images,
      metadata: {
        brand: built.brand,
        product: built.product,
        topic: built.topic,
        language: built.language,
        platform: built.platform,
        objective: built.objective,
      },
    },
  },
];

const source = $('Parse Carousel Output').first().json;

const content = source.content || {};
const slides = Array.isArray(content.slides) ? content.slides : [];

if (!slides.length) {
  throw new Error('No slides found to prepare image generation');
}

return slides.map((slide, index) => {
  const slideNumber = Number(slide.slideNumber || index + 1);

  return {
    json: {
